function Insert($jsonArr) {
    $bodyBytes = [System.Text.Encoding]::UTF8.GetBytes($jsonArr)
    try {
        $r = Invoke-WebRequest -Uri "$supabaseUrl/rest/v1/companies" -Method POST -Headers $postHeaders -Body $bodyBytes -UseBasicParsing
